import React from 'react';
import { Link, useLocation } from 'react-router-dom';

const Sidebar = () => {
  const { pathname } = useLocation();

  const links = [
    { to: '/dashboard', label: 'Dashboard' },
    { to: '/products', label: 'Products' },
    { to: '/orders', label: 'Orders' },
    { to: '/customers', label: 'Customers' },
    { to: '/analytics', label: 'Analytics' },
    { to: '/promotions', label: 'Promotions' },
    { to: '/feedback', label: 'Feedback' },
    { to: '/support', label: 'Support' },
  ];

  return (
    <aside className="bg-gray-950 text-white w-64 h-full fixed top-0 left-0 shadow-md">
      <div className="p-6">
        <h2 className="text-lg font-semibold mb-6">Admin Dashboard</h2>
        <nav className="flex flex-col gap-4">
          {links.map(link => (
            <Link
              key={link.to}
              to={link.to}
              className={`px-4 py-2 rounded-lg transition-colors ${pathname === link.to ? 'bg-indigo-600' : 'hover:bg-gray-800'}`}
            >
              {link.label}
            </Link>
          ))}
        </nav>
      </div>
    </aside>
  );
};

export default Sidebar;
